"use strict";(self.webpackChunkengsoft_knowledge_base=self.webpackChunkengsoft_knowledge_base||[]).push([[3199],{7695(a){a.exports=JSON.parse('{"tag":{"label":"legislacao","permalink":"/engsoft-knowledge-base/tags/legislacao","allTagsPath":"/engsoft-knowledge-base/tags","count":13,"items":[{"id":"legislacao/README","title":"Legislacao","description":"Esta pasta organiza a base normativa que sustenta processos academicos da graduacao, com atos institucionais da UFMS e referencias nacionais. O foco e facilitar consulta por tema e tipo de ato.","permalink":"/engsoft-knowledge-base/legislacao/"},{"id":"legislacao/legislacao-avaliacao/README","title":"Legislacao de Avaliacao","description":"Esta pasta reune normas e referencias de regulacao, avaliacao e supervisao institucional e de cursos. Ela apoia consultas sobre credenciamento, reconhecimento e fluxos de monitoramento regulatorio.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-avaliacao/"},{"id":"legislacao/legislacao-estagio/README","title":"Legislacao de Estagio","description":"Esta pasta organiza atos e regulamentos sobre estagio curricular obrigatorio e nao obrigatorio. O objetivo e apoiar consultas sobre regras, papeis e procedimentos formais de acompanhamento.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-estagio/"},{"id":"legislacao/legislacao-formacao-de-professores/README","title":"Legislacao de Formacao de Professores","description":"Esta pasta reune normas e referencias sobre politicas de formacao inicial e continuada de professores. O conjunto apoia leitura de programas e instrumentos institucionais ligados ao tema.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-formacao-de-professores/"},{"id":"legislacao/legislacao-ingresso/README","title":"Legislacao de Ingresso","description":"Esta pasta organiza documentos sobre formas de ingresso e mobilidade academica. O foco e reunir atos que orientam acesso inicial, ocupacao de vagas e modalidades relacionadas.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-ingresso/"},{"id":"legislacao/legislacao-professor-substituto/README","title":"Legislacao de Professor Substituto","description":"Esta pasta concentra atos sobre solicitacao, selecao e contratacao de professor substituto. O conteudo apoia fluxos administrativos e decisao em unidades academicas.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-professor-substituto/"},{"id":"legislacao/legislacao-educacional-nacional/README","title":"Legislacao Educacional Nacional","description":"Esta pasta concentra marcos normativos nacionais que orientam a educacao superior e a formacao de cursos. Aqui estao referencias de orgaos nacionais e diretrizes amplas de politica educacional.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-educacional-nacional/"},{"id":"legislacao/legislacao-geral-graduacao/README","title":"Legislacao Geral da Graduacao","description":"Esta pasta reune regulamentos amplos da graduacao, com normas de organizacao academica, trajetoria discente e funcionamento de cursos. E uma referencia central para consultas recorrentes da coordenacao.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-geral-graduacao/"},{"id":"legislacao/legislacao-geral-da-ufms/README","title":"Legislacao Geral da UFMS","description":"Esta pasta concentra atos estruturantes da UFMS, como referencias de governanca, organizacao e funcionamento institucional. Sao documentos-base para contextualizar regras academicas especificas.","permalink":"/engsoft-knowledge-base/legislacao/legislacao-geral-da-ufms/"},{"id":"legislacao/normas/README","title":"Normas","description":"Esta pasta reune instrucoes normativas e atos operacionais usados no dia a dia academico da graduacao. Ela funciona como referencia pratica para procedimentos com alta recorrencia administrativa.","permalink":"/engsoft-knowledge-base/legislacao/normas/"},{"id":"legislacao/programas/programa-de-estudantes-convenio-de-graduacao-pec-g/README","title":"Programa PEC-G","description":"Esta pasta concentra os documentos do Programa de Estudantes-Convenio de Graduacao (PEC-G), incluindo regulamentos e materiais institucionais de orientacao.","permalink":"/engsoft-knowledge-base/legislacao/programas/programa-de-estudantes-convenio-de-graduacao-pec-g/"},{"id":"legislacao/programas/README","title":"Programas","description":"Esta pasta agrupa regulamentos e atos de programas academicos vinculados a graduacao. O objetivo e facilitar a consulta de regras especificas por programa.","permalink":"/engsoft-knowledge-base/legislacao/programas/"},{"id":"legislacao/regulamentos-de-ccnd-da-graduacao/README","title":"Regulamentos de CCND da Graduacao","description":"Esta pasta reune regulamentos centrais que estruturam cursos de graduacao no ambito da universidade. Sao documentos-chave para entendimento de regras academicas nucleares.","permalink":"/engsoft-knowledge-base/legislacao/regulamentos-de-ccnd-da-graduacao/"}],"unlisted":false}}')}}]);